import React from "react";
import "./portfolio-item.css";
import "../styles/global.css"
import { LogoGithub } from "react-ionicons";
import { Book } from "react-ionicons";

class PortfolioItem extends React.Component {
    constructor(props) {
        super(props);
        this.thumbnail = props.thumbnail;
        this.title = props.title;
        this.description = props.description;
        this.github_link = props.github_link;
        
        this.state = { hidden: true };
        this.readAboutToggle = () => {
            this.setState({ hidden: !this.state.hidden });
        };
    }

    render() {
        return (
            <div className="portfolio-item">
                <a href={this.github_link}><LogoGithub></LogoGithub></a>
                <img src={this.thumbnail} alt=""></img>
                <section className="portfolio-item-inner">
                    <h2 className="portfolio-item-title">{this.title}</h2>
                    {
                        console.log(this.description)
                    }
                    {!this.state.hidden && (
                        <p>{this.description}</p>
                    )}


                    <h4 onClick={this.readAboutToggle}>
                    {!this.state.hidden && (<p>.hide</p>)}
                    {this.state.hidden  && (<p>.read_more</p>)}
                    </h4>

                </section>
            </div>
        );
    }

}

export default PortfolioItem;
